using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class QuotesTraining : TrainingContentBase
{
    public QuotesTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Quotes Overview",
            Slug = "quotes-overview",
            Summary = "What quotes are, how they differ from estimates, line item structure, lifecycle statuses, and conversion to sales orders.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/quotes"]""",
            Tags = """["quotes","sales"]""",
            ContentJson = """{"body":"## Quotes Overview\n\nThe Quotes module manages binding fixed-price commitments to your customers. A quote is a formal document that lists specific parts, quantities, and unit prices — once accepted by the customer, it becomes the contractual basis for a sales order.\n\n### Quotes vs Estimates\n\nQB Engineer has two distinct pricing documents, both stored in the same underlying table but serving very different purposes:\n\n- **Estimates** are non-binding ballpark figures. They have a single lump-sum amount, no line items, and no formal acceptance workflow. Estimates live on the customer detail page under the Estimates tab.\n- **Quotes** are binding fixed-price commitments. They are line-itemized (each line specifies a part, quantity, and unit price), have a formal lifecycle (Draft → Sent → Accepted → Converted to Order), and can be converted into a sales order.\n\nAn estimate can be converted into a quote when the customer wants to move forward. The resulting quote retains a link back to the source estimate for traceability.\n\n### Line Items\n\nEvery quote must have at least one line item. Each line specifies:\n- **Part** — selected from your parts catalog via autocomplete search\n- **Description** — auto-filled from the part record\n- **Quantity** — how many units\n- **Unit Price** — defaults to the part's list price if one is configured; can be overridden\n- **Line Total** — calculated as Quantity × Unit Price\n\nThe quote's financial summary is computed from its lines:\n- **Subtotal** — sum of all line totals\n- **Tax** — subtotal multiplied by the tax rate (auto-filled from the customer's state; editable)\n- **Grand Total** — subtotal plus tax\n\n### Quote Lifecycle\n\nQuotes follow a defined status progression:\n\n1. **Draft** (gray chip) — Initial state. The quote can be edited, lines added or removed, and deleted if no longer needed.\n2. **Sent** (blue chip) — The quote has been sent to the customer. Set via the Send action button. Records the sent date.\n3. **Accepted** (green chip) — The customer has accepted the quote. Set via the Accept action button. Records the accepted date.\n4. **Declined** (red chip) — The customer declined the quote. Set via the Reject action button with a confirmation dialog.\n5. **Expired** (yellow chip) — The quote passed its expiration date without being accepted.\n6. **Converted to Order** (purple/primary chip) — The accepted quote has been converted into a sales order. The quote links to the resulting sales order.\n\n### Status Transition Rules\n\n- **Send** is available only when status is Draft\n- **Accept** and **Reject** are available only when status is Sent\n- **Convert to Order** is available only when status is Accepted\n- **Delete** is available only when status is Draft (soft delete)\n- Quotes cannot move backward in the lifecycle\n\n### Conversion to Sales Order\n\nWhen you convert an accepted quote, the system:\n1. Creates a new sales order with lines matching the quote's line items\n2. Links the quote to the new sales order (visible in the quote detail as \"Linked Order\")\n3. Updates the quote status to Converted to Order\n4. The sales order inherits the customer, shipping address, and line item details\n\n### Tax Rate Auto-Fill\n\nWhen you select a customer on the quote form, the system looks up the applicable sales tax rate based on the customer's state. The tax rate field is auto-filled with this value (shown with a badge like \"CA 7.25%\"). You can manually override the rate if needed.\n\n### When to Use Quotes\n\n- When a customer requests formal pricing with specific parts and quantities\n- When you need a binding price commitment before creating a sales order\n- When converting an estimate into a detailed line-itemized proposal\n- When you need to track the acceptance/rejection history of pricing proposals","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Quotes — Guided Tour",
            Slug = "quotes-walkthrough",
            Summary = "A guided tour of the quotes list page: search, filters, data table, creating quotes, and viewing quote details.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/quotes"]""",
            Tags = """["quotes","sales","walkthrough"]""",
            ContentJson = """{"appRoute":"/quotes","startButtonLabel":"Tour Quotes","steps":[{"element":"[data-testid='new-quote-btn']","popover":{"title":"New Quote Button","description":"Click here to create a new quote. A split-layout dialog opens with line items on the left and quote details (customer, expiration, tax rate, notes) on the right. You must add at least one line item before saving.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Quotes","description":"Search quotes by quote number or customer name. Type your search term and press Enter to filter the list.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Status Filter","description":"Filter quotes by status: Draft, Sent, Accepted, Declined, Expired, or Converted to Order. Select 'All Statuses' to clear the filter.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Quotes Table","description":"Shows all quotes with columns for quote number, customer, status (color-coded chip), line count, total amount, expiration date, and created date. Click any row to open the quote detail dialog. Click column headers to sort. Use the gear icon to manage column visibility.","side":"top"}},{"element":"[data-testid='new-quote-btn']","popover":{"title":"Quote Creation Workflow","description":"When creating a quote: 1) Select a customer (tax rate auto-fills from their state). 2) Use the autocomplete to search for parts and add line items. Unit price defaults to the part's list price. 3) Optionally set an expiration date and add notes. 4) Review the subtotal, tax, and grand total in the summary section before saving.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Quotes Field Reference",
            Slug = "quotes-field-reference",
            Summary = "Complete reference for every field, button, status, chip color, validation rule, and action in the Quotes module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/quotes"]""",
            Tags = """["quotes","sales","reference"]""",
            ContentJson = """{"title":"Quotes Field Reference","groups":[{"heading":"Quote Form Fields (Create Dialog — Sidebar)","items":[{"label":"Customer (required)","value":"Dropdown select. Choose the customer this quote is for. When selected, the tax rate auto-fills based on the customer's state sales tax rate. data-testid: quote-customer"},{"label":"Expiration Date","value":"Date picker, optional. When the quote expires if not accepted. Quotes past this date can be marked Expired. data-testid: quote-expiry"},{"label":"Tax Rate (required)","value":"Number input with % suffix. Auto-filled from the customer's state tax rate (shown with a badge like 'CA 7.25%'). Can be manually overridden. Applied to the subtotal to calculate tax amount. Default: 0. data-testid: quote-tax-rate"},{"label":"Notes","value":"Textarea, optional. Free-form notes visible in the quote detail. 3 rows. data-testid: quote-notes"}]},{"heading":"Line Item Fields (Create Dialog — Main Area)","items":[{"label":"Part (required)","value":"Autocomplete search. Search by part number or description. Displays as 'PartNumber — Description'. When selected, the unit price auto-fills from the part's list price (shown with a 'LIST' badge). data-testid: quote-line-part"},{"label":"Qty (required)","value":"Number input. Quantity of parts for this line. Minimum 1. data-testid: quote-line-qty"},{"label":"Price (required)","value":"Number input. Unit price per part. Defaults to the part's list price when a part is selected; manually editable. Minimum 0. data-testid: quote-line-price"},{"label":"Add button","value":"Adds the current part/qty/price as a new line item. Disabled when the line form is invalid. Resets the line form after adding. data-testid: quote-add-line-btn"},{"label":"Remove (X) button","value":"Red icon button on each line row. Removes that line item from the quote."}]},{"heading":"Computed Summary Fields (Create Dialog — Sidebar)","items":[{"label":"Subtotal","value":"Sum of all line totals (Quantity × Unit Price for each line). Read-only."},{"label":"Tax","value":"Subtotal × Tax Rate %. Displayed with the current tax rate percentage. Read-only."},{"label":"Total","value":"Subtotal + Tax. Grand total displayed in bold. Read-only."}]},{"heading":"Quote Statuses and Chip Colors","items":[{"label":"Draft (gray — chip--muted)","value":"Initial state. Quote is editable. Can be sent or deleted."},{"label":"Sent (blue — chip--info)","value":"Quote has been sent to the customer. Records the sent date. Can be accepted or rejected."},{"label":"Accepted (green — chip--success)","value":"Customer accepted the quote. Records the accepted date. Can be converted to a sales order."},{"label":"Declined (red — chip--error)","value":"Customer declined the quote. Terminal state — no further actions available."},{"label":"Expired (yellow — chip--warning)","value":"Quote passed its expiration date without acceptance. Terminal state."},{"label":"Converted to Order (purple — chip--primary)","value":"Quote was converted to a sales order. Shows a link to the generated sales order. Terminal state."}]},{"heading":"Table Columns (List Page)","items":[{"label":"Quote #","value":"Sortable. Auto-generated quote number displayed in monospace font. Width: 120px."},{"label":"Customer","value":"Sortable. Customer name from the linked customer record."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip showing current lifecycle status. Width: 140px."},{"label":"Lines","value":"Sortable, center-aligned. Number of line items on the quote. Width: 70px."},{"label":"Total","value":"Sortable, right-aligned. Grand total (subtotal + tax) formatted as currency. Width: 100px."},{"label":"Expires","value":"Sortable, date type. Expiration date in MM/dd/yyyy format. Shows '---' if no expiration set. Width: 110px."},{"label":"Created","value":"Sortable, date type. Creation date in MM/dd/yyyy format. Width: 110px."}]},{"heading":"Detail Dialog Fields","items":[{"label":"Quote Number","value":"Displayed in the header with a request_quote icon. Auto-generated, read-only."},{"label":"Customer","value":"Clickable entity link to the customer detail page."},{"label":"Status","value":"Color-coded chip in the info grid."},{"label":"Expiration Date","value":"Shown if set. Formatted as MM/dd/yyyy."},{"label":"Sent Date","value":"Shown only after the quote has been sent. Formatted as MM/dd/yyyy."},{"label":"Accepted Date","value":"Shown only after the quote has been accepted. Formatted as MM/dd/yyyy."},{"label":"Linked Order","value":"Shown only after conversion. Clickable entity link to the generated sales order."},{"label":"Notes","value":"Shown only if notes were entered. Free-form text block."},{"label":"Line Items Table","value":"Part number (monospace), description, quantity, unit price, and line total for each line."},{"label":"Subtotal / Tax / Total","value":"Financial summary section at the bottom of the line items."},{"label":"Created / Updated","value":"Timestamps in MM/dd/yyyy format."},{"label":"Activity Log","value":"Chronological activity feed at the bottom of the detail panel."}]},{"heading":"Buttons and Actions","items":[{"label":"New Quote (list page, primary)","value":"Opens the create dialog. data-testid: new-quote-btn"},{"label":"Save / Create Quote (dialog, primary)","value":"Creates the quote. Disabled when form is invalid, no line items exist, or save is in progress. Hover shows validation popover. data-testid: quote-save-btn"},{"label":"Cancel (dialog)","value":"Closes the create dialog without saving."},{"label":"Send (detail, primary)","value":"Marks the quote as Sent. Only available when status is Draft. data-testid: quote-send-btn"},{"label":"Accept (detail, primary)","value":"Marks the quote as Accepted. Only available when status is Sent. data-testid: quote-accept-btn"},{"label":"Reject (detail)","value":"Marks the quote as Declined. Only available when status is Sent. Opens a confirmation dialog before proceeding. data-testid: quote-reject-btn"},{"label":"Convert to Order (detail, primary)","value":"Converts the accepted quote into a sales order. Only available when status is Accepted. Creates the sales order and links it to the quote. data-testid: quote-convert-btn"},{"label":"Delete (detail, danger)","value":"Soft-deletes the quote. Only available when status is Draft. Opens a confirmation dialog before proceeding. data-testid: quote-delete-btn"},{"label":"Close (detail, icon)","value":"Closes the detail dialog."},{"label":"Row click (table)","value":"Opens the quote detail dialog for the clicked row."}]},{"heading":"Validation Rules","items":[{"label":"Customer","value":"Required. Must select a customer from the dropdown."},{"label":"Tax Rate","value":"Required. Must be a number >= 0. Entered as a percentage (e.g., 7.25 for 7.25%)."},{"label":"Line Items","value":"At least one line item is required. The save button is disabled and the validation popover shows 'At least one line item is required' if no lines exist."},{"label":"Line — Part","value":"Required for each line. Must select a part from the autocomplete."},{"label":"Line — Quantity","value":"Required. Must be >= 1."},{"label":"Line — Unit Price","value":"Required. Must be >= 0."},{"label":"Expiration Date","value":"Optional. No validation constraints."},{"label":"Notes","value":"Optional. No length restrictions."}]},{"heading":"Smart Defaults and Auto-Fill","items":[{"label":"Tax Rate Auto-Fill","value":"When a customer is selected, the system looks up the sales tax rate for the customer's state and auto-fills the tax rate field. A badge (e.g., 'CA 7.25%') appears next to the field. Manually editing the rate clears the auto-fill badge."},{"label":"Unit Price Auto-Fill","value":"When a part is selected for a line item, the unit price auto-fills from the part's default/list price. A 'LIST' badge appears next to the price field. Manually editing the price clears the badge."},{"label":"Line Form Reset","value":"After adding a line item, the line form resets to: Part = empty, Quantity = 1, Unit Price = 0."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Quotes Knowledge Check",
            Slug = "quotes-quiz",
            Summary = "Test your knowledge of the Quotes module: lifecycle, line items, statuses, conversion, tax auto-fill, and common workflows.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/quotes"]""",
            Tags = """["quotes","sales","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"qt1","text":"A customer asks for a rough ballpark on a project before committing to specifics. Which document type should you create?","options":[{"id":"a","text":"A Quote with a single line item for the estimated total"},{"id":"b","text":"An Estimate — a non-binding ballpark figure with a single lump-sum amount","isCorrect":true},{"id":"c","text":"A Sales Order with a 'Pending' status"},{"id":"d","text":"A Quote in Draft status with no line items"}],"explanation":"Estimates are non-binding ballpark figures with a single amount. Quotes are binding, line-itemized commitments. Use an Estimate first, then convert it to a Quote when the customer wants detailed pricing."},{"id":"qt2","text":"What is the minimum requirement to save a new quote?","options":[{"id":"a","text":"A customer must be selected and at least one line item must be added","isCorrect":true},{"id":"b","text":"Only a customer selection is required — line items can be added later"},{"id":"c","text":"A customer, expiration date, and at least two line items"},{"id":"d","text":"A quote number must be manually entered along with the customer"}],"explanation":"The save button is disabled until a customer is selected and at least one line item exists. The validation popover shows 'At least one line item is required' if no lines have been added. Quote numbers are auto-generated."},{"id":"qt3","text":"You select 'Acme Corp' as the customer and notice the tax rate auto-fills to 7.25% with a badge showing 'CA 7.25%'. What happened?","options":[{"id":"a","text":"The system looked up the sales tax rate for California (the customer's state) and auto-filled it","isCorrect":true},{"id":"b","text":"7.25% is the default tax rate for all customers"},{"id":"c","text":"The tax rate was copied from Acme Corp's last quote"},{"id":"d","text":"The rate was pulled from the federal tax table"}],"explanation":"When you select a customer, the system looks up the applicable sales tax rate based on the customer's state. The badge (e.g., 'CA 7.25%') confirms the source. You can manually override the rate if needed."},{"id":"qt4","text":"When adding a line item, you select a part and see a 'LIST' badge appear next to the unit price. What does this indicate?","options":[{"id":"a","text":"The price was auto-filled from the part's list/default price and can be overridden","isCorrect":true},{"id":"b","text":"The price is locked and cannot be changed"},{"id":"c","text":"The part is on a special price list for this customer"},{"id":"d","text":"The price includes a volume discount"}],"explanation":"When you select a part, the unit price auto-fills from the part's default/list price. The 'LIST' badge indicates this is the catalog price. Manually editing the price clears the badge — you can always override the default."},{"id":"qt5","text":"A quote is currently in 'Sent' status. Which actions are available?","options":[{"id":"a","text":"Accept and Reject only","isCorrect":true},{"id":"b","text":"Send, Accept, Reject, and Delete"},{"id":"c","text":"Accept, Reject, Convert to Order, and Delete"},{"id":"d","text":"Only Convert to Order"}],"explanation":"When a quote is Sent, only Accept and Reject are available. Send is only for Draft quotes. Convert to Order requires Accepted status. Delete is only available for Draft quotes."},{"id":"qt6","text":"What happens when you click 'Convert to Order' on an accepted quote?","options":[{"id":"a","text":"The system creates a new sales order with lines matching the quote, links the quote to the order, and updates the quote status to Converted to Order","isCorrect":true},{"id":"b","text":"The quote is renamed to a sales order — same record, different label"},{"id":"c","text":"A blank sales order is created and you must manually copy the line items"},{"id":"d","text":"The quote is archived and a notification is sent to create a sales order manually"}],"explanation":"Converting creates a new sales order with lines matching the quote's line items, inheriting the customer and details. The quote links to the new sales order (visible as 'Linked Order' in the detail) and its status changes to Converted to Order."},{"id":"qt7","text":"You want to delete a quote that has already been sent to the customer. Can you?","options":[{"id":"a","text":"Yes — any quote can be deleted at any time"},{"id":"b","text":"No — only Draft quotes can be deleted. Sent, Accepted, Declined, and Expired quotes cannot be deleted.","isCorrect":true},{"id":"c","text":"Yes, but only if the customer hasn't responded within 30 days"},{"id":"d","text":"No — quotes can never be deleted, only archived"}],"explanation":"The Delete action is only available when the quote status is Draft. Once a quote has been sent, it becomes part of the audit trail and cannot be deleted. This ensures you maintain a complete record of all pricing communications."},{"id":"qt8","text":"Which chip color represents a quote that has been declined by the customer?","options":[{"id":"a","text":"Yellow (warning)"},{"id":"b","text":"Gray (muted)"},{"id":"c","text":"Red (error)","isCorrect":true},{"id":"d","text":"Blue (info)"}],"explanation":"Declined quotes show a red chip (chip--error). The full color mapping: Draft = gray, Sent = blue, Accepted = green, Declined = red, Expired = yellow, Converted to Order = purple/primary."},{"id":"qt9","text":"An estimate was converted to a quote. Where can you see the link back to the original estimate?","options":[{"id":"a","text":"In the quote detail dialog — the sourceEstimateId field links back to the originating estimate","isCorrect":true},{"id":"b","text":"There is no link — estimates and quotes are completely separate"},{"id":"c","text":"Only in the database — the UI doesn't show estimate-to-quote links"},{"id":"d","text":"In the customer's activity log only"}],"explanation":"When an estimate is converted to a quote, the resulting quote stores a sourceEstimateId that links back to the originating estimate. This provides full traceability of the pricing history from initial ballpark to formal commitment."},{"id":"qt10","text":"How is the grand total on a quote calculated?","options":[{"id":"a","text":"It is manually entered by the user"},{"id":"b","text":"Subtotal (sum of all line totals) plus Tax (subtotal × tax rate percentage)","isCorrect":true},{"id":"c","text":"Sum of all line quantities multiplied by a single unit price"},{"id":"d","text":"The total from the linked estimate plus a markup percentage"}],"explanation":"The grand total is computed: Subtotal = sum of (Quantity × Unit Price) for each line. Tax = Subtotal × Tax Rate %. Grand Total = Subtotal + Tax. All three values are displayed in the summary section."},{"id":"qt11","text":"You're on the quotes list page and want to see only quotes that have been accepted but not yet converted. How do you filter?","options":[{"id":"a","text":"Use the status filter dropdown and select 'Accepted'","isCorrect":true},{"id":"b","text":"Type 'accepted' in the search box"},{"id":"c","text":"Click the column header to sort by status, then scroll to the Accepted section"},{"id":"d","text":"There is no way to filter by status — you must scan the full list"}],"explanation":"The status filter dropdown on the quotes list page lets you filter by any single status. Select 'Accepted' to see only accepted quotes that haven't been converted yet. The table also supports column-level status filtering via the column header filter."},{"id":"qt12","text":"What columns are visible in the quotes data table by default?","options":[{"id":"a","text":"Quote #, Customer, Status, Lines, Total, Expires, and Created","isCorrect":true},{"id":"b","text":"Quote #, Customer, and Total only"},{"id":"c","text":"Quote #, Customer, Status, Assigned To, Priority, and Due Date"},{"id":"d","text":"Quote #, Description, Amount, Tax, and Grand Total"}],"explanation":"The quotes table shows seven columns: Quote # (monospace), Customer name, Status (color-coded chip), Lines count (center-aligned), Total (currency, right-aligned), Expires (date), and Created (date). All columns are sortable. You can manage column visibility via the gear icon."}]}"""
        });

        Log.Information("Seeded Quotes training modules");
    }
}
